# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json

players = {}
items = {}

async def handler(websocket, path):
    global players, items
    
    data = await websocket.recv()
    message = json.loads(data)
    action = message.get('action')
    user = message.get('user')
    
    if action == 'connect':
        players[user] = {'socket':websocket, 'inventory': []}
        
    elif action == 'add-item':
        if user in players:
            item = message.get('item')
            if item not in items:
                items[item] = {'owner': user, 'is_transferable':True}
                players[user]['inventory'].append(item)
                
    elif action == 'remove-item':
        if user in players:
            item = message.get('item')
            if item in items and items[item]['owner'] == user:
                players[user]['inventory'].remove(item)
                del items[item]
                
    elif action == 'trade':
        if user in players:
            receiver = message.get('receiver')
            if receiver in players:
                item = message.get('item')
                if item in items and items[item]['owner'] == user and items[item]['is_transferable']:
                    players[user]['inventory'].remove(item)
                    players[receiver]['inventory'].append(item)
                    items[item]['owner'] = receiver
    
    await websocket.send(json.dumps({'players': players, 'items': items}))

start_server = websockets.serve(handler, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()